// ─── UTILS ───────────────────────────────────────────────────────────────────
// Feriados de Portugal Continental (fixos + Páscoa calculada)
function calcEaster(year) {
  const a = year % 19,
    b = Math.floor(year / 100),
    c = year % 100,
    d = Math.floor(b / 4),
    e = b % 4,
    f = Math.floor((b + 8) / 25),
    g = Math.floor((b - f + 1) / 3),
    h = (19 * a + b - d - g + 15) % 30,
    i = Math.floor(c / 4),
    k = c % 4,
    l = (32 + 2 * e + 2 * i - h - k) % 7,
    m = Math.floor((a + 11 * h + 22 * l) / 451),
    month = Math.floor((h + l - 7 * m + 114) / 31),
    day = (h + l - 7 * m + 114) % 31 + 1;
  return new Date(year, month - 1, day);
}
function getFeriados(year) {
  const e = calcEaster(year);
  // Usa componentes locais para evitar desfasamento UTC (Portugal UTC+1)
  const localStr = dt => `${dt.getFullYear()}-${String(dt.getMonth() + 1).padStart(2, "0")}-${String(dt.getDate()).padStart(2, "0")}`;
  const addE = n => {
    const x = new Date(e);
    x.setDate(x.getDate() + n);
    return localStr(x);
  };
  return new Set([`${year}-01-01`, `${year}-04-25`, `${year}-05-01`, `${year}-06-10`, `${year}-08-15`, `${year}-10-05`, `${year}-11-01`, `${year}-12-01`, `${year}-12-08`, `${year}-12-25`, addE(-2),
  // Sexta-feira Santa
  localStr(e),
  // Páscoa
  addE(60) // Corpo de Deus
  ]);
}
function localDateStr(d) {
  return `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, "0")}-${String(d.getDate()).padStart(2, "0")}`;
}
function isWorkday(d) {
  if (d.getDay() === 0 || d.getDay() === 6) return false;
  return !getFeriados(d.getFullYear()).has(localDateStr(d));
}
function addDays(s, n) {
  // Avança n dias úteis (excluindo fins-de-semana e feriados PT)
  if (!s) return s;
  const d = new Date(s + "T12:00:00");
  let count = 0;
  while (count < n) {
    d.setDate(d.getDate() + 1);
    if (isWorkday(d)) count++;
  }
  return d.toISOString().slice(0, 10);
}
function fimObra(o) {
  return addDays(o.inicio, Math.max(0, (o.duracao || 1) - 1));
}
function toDate(s) {
  return new Date(s + "T00:00:00");
}
function fmt(d) {
  if (!d) return "—";
  return toDate(d).toLocaleDateString("pt-PT", {
    day: "2-digit",
    month: "2-digit",
    year: "numeric"
  });
}

