// ─── AUTENTICAÇÃO MSAL v2 ────────────────────────────────────────────────────
let _msalInstance = null;
let _authInProgress = false;
function getRedirectUri() {
  const base = window.location.href.split("?")[0].split("#")[0];
  return base.endsWith("/") ? base : base + "/";
}
async function getMSAL() {
  if (_msalInstance) return _msalInstance;
  if (!window.msal) throw new Error("MSAL não carregado");
  _msalInstance = new window.msal.PublicClientApplication({
    auth: {
      clientId: SP_CONFIG.clientId,
      authority: `https://login.microsoftonline.com/${SP_CONFIG.tenantId}`,
      redirectUri: getRedirectUri(),
      navigateToLoginRequestUrl: false
    },
    cache: {
      cacheLocation: "sessionStorage",
      storeAuthStateInCookie: true
    }
  });
  return _msalInstance;
}
async function getAccessToken() {
  if (_accessToken) return _accessToken;
  if (_authInProgress) return null;
  const msalInstance = await getMSAL();
  const scopes = ["https://graph.microsoft.com/Sites.ReadWrite.All"];
  const redirectUri = getRedirectUri();

  // Processa o token de retorno após redirect do login Microsoft
  try {
    const redirectResp = await msalInstance.handleRedirectPromise();
    if (redirectResp?.accessToken) {
      _accessToken = redirectResp.accessToken;
      _authInProgress = false;
      return _accessToken;
    }
  } catch (e) {
    console.warn("handleRedirectPromise:", e.message);
  }
  const accounts = msalInstance.getAllAccounts();
  if (accounts.length > 0) {
    try {
      const resp = await msalInstance.acquireTokenSilent({
        scopes,
        account: accounts[0],
        redirectUri
      });
      _accessToken = resp.accessToken;
      return _accessToken;
    } catch (e) {
      _authInProgress = true;
      await msalInstance.acquireTokenRedirect({
        scopes,
        account: accounts[0],
        redirectUri
      });
      return null;
    }
  } else {
    _authInProgress = true;
    await msalInstance.loginRedirect({
      scopes,
      redirectUri
    });
    return null;
  }
}

// ─── GRAPH API — HELPERS ──────────────────────────────────────────────────────
async function graphGet(url) {
  const token = await getAccessToken();
  const res = await fetch(`https://graph.microsoft.com/v1.0${url}`, {
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json"
    }
  });
  if (!res.ok) throw new Error(`Graph GET falhou: ${res.status} ${url}`);
  return res.json();
}
async function graphPost(url, body) {
  const token = await getAccessToken();
  const res = await fetch(`https://graph.microsoft.com/v1.0${url}`, {
    method: "POST",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json"
    },
    body: JSON.stringify(body)
  });
  if (!res.ok) { const e = await res.json().catch(()=>({})); throw new Error(`Graph POST falhou: ${res.status} — ${e?.error?.message || e?.error?.code || url}`); }
  return res.json();
}
async function graphPatch(url, body) {
  const token = await getAccessToken();
  const res = await fetch(`https://graph.microsoft.com/v1.0${url}`, {
    method: "PATCH",
    headers: {
      Authorization: `Bearer ${token}`,
      "Content-Type": "application/json"
    },
    body: JSON.stringify(body)
  });
  if (!res.ok) throw new Error(`Graph PATCH falhou: ${res.status} ${url}`);
  return res.json();
}
async function graphDelete(url) {
  const token = await getAccessToken();
  const res = await fetch(`https://graph.microsoft.com/v1.0${url}`, {
    method: "DELETE",
    headers: {
      Authorization: `Bearer ${token}`
    }
  });
  if (!res.ok) throw new Error(`Graph DELETE falhou: ${res.status} ${url}`);
}

// ─── RESOLVER SITE ID E LIST IDs ──────────────────────────────────────────────
async function resolverSiteId() {
  if (_siteId) return _siteId;
  const url = new URL(SP_CONFIG.siteUrl);
  const hostname = url.hostname;
  const sitePath = url.pathname;
  const apiUrl = `/sites/${hostname}:${sitePath}`;
  console.log("Resolving site:", apiUrl);
  const data = await graphGet(apiUrl);
  // O Site ID pode vir no formato "hostname,siteId,webId" — usamos apenas a parte do siteId
  const rawId = data.id;
  console.log("Raw Site ID:", rawId);
  // Formato correcto para chamadas subsequentes é o id completo tal como vem
  _siteId = rawId;
  return _siteId;
}
async function resolverListId(nomeLista) {
  if (_listIds[nomeLista]) return _listIds[nomeLista];
  const siteId = await resolverSiteId();
  const data = await graphGet(`/sites/${siteId}/lists?$select=id,displayName&$top=100`);
  console.log("Listas disponíveis:", data.value?.map(l => l.displayName));
  // Normaliza para comparação: remove espaços extra, converte todos os travessões para hífen simples
  const normalizar = s => s.toLowerCase().trim().replace(/\u2013|\u2014|\u2012/g, "-") // en-dash, em-dash → hífen
  .replace(/\s+/g, " ");
  const nomeNorm = normalizar(nomeLista);
  const lista = data.value?.find(l => normalizar(l.displayName) === nomeNorm);
  if (!lista) throw new Error(`Lista não encontrada: "${nomeLista}". Disponíveis: ${data.value?.map(l => l.displayName).join(", ")}`);
  _listIds[nomeLista] = lista.id;
  return lista.id;
}

