// ─── CRUD — REGISTOS DE HORAS ─────────────────────────────────────────────────
async function spListarRegistos() {
  const siteId = await resolverSiteId();
  const listId = await resolverListId(SP_CONFIG.listaHoras);
  const data = await graphGet(`/sites/${siteId}/lists/${listId}/items?$expand=fields&$top=1000`);
  return (data.value || []).map(spItemParaRegisto);
}
async function spCriarRegisto(registo, obras) {
  const siteId = await resolverSiteId();
  const listId = await resolverListId(SP_CONFIG.listaHoras);
  const item = await graphPost(`/sites/${siteId}/lists/${listId}/items`, {
    fields: registoParaSPFields(registo, obras)
  });
  return spItemParaRegisto(item);
}
async function spActualizarRegisto(registo, obras) {
  const siteId = await resolverSiteId();
  const listId = await resolverListId(SP_CONFIG.listaHoras);
  await graphPatch(`/sites/${siteId}/lists/${listId}/items/${registo.spId || registo.id}/fields`, registoParaSPFields(registo, obras));
}
async function spApagarRegisto(spId) {
  const siteId = await resolverSiteId();
  const listId = await resolverListId(SP_CONFIG.listaHoras);
  await graphDelete(`/sites/${siteId}/lists/${listId}/items/${spId}`);
}

// ─── CRUD — FUNCIONÁRIOS ─────────────────────────────────────────────────────
async function spListarFuncionarios() {
  try {
    const siteId = await resolverSiteId();
    const listId = await resolverListId(SP_CONFIG.listaFuncionarios);
    const data = await graphGet(`/sites/${siteId}/lists/${listId}/items?$expand=fields&$top=200`);
    const items = (data.value || []).map(item => ({
      nome: item.fields?.Nome || item.fields?.Title || "",
      custoHora: parseFloat(item.fields?.CustoHora) || 0,
      ativo: item.fields?.Ativo !== false
    })).filter(f => f.nome && f.ativo);
    if (items.length > 0) {
      // Actualiza as constantes globais com os dados do SharePoint
      FUNCIONARIOS = items.map(f => f.nome);
      CUSTO_HORA = Object.fromEntries(items.map(f => [f.nome, f.custoHora]));
      console.log("Funcionários carregados do SharePoint:", FUNCIONARIOS);
    }
    return items;
  } catch (e) {
    console.warn("Erro ao carregar funcionários:", e.message, "— a usar valores locais");
    return FUNCIONARIOS.map(nome => ({
      nome,
      custoHora: CUSTO_HORA[nome] || 0,
      ativo: true
    }));
  }
}

// ─── LOOKUP DE SINISTROS (lista real do SharePoint) ──────────────────────────
// Pesquisa na lista "Listagem Sinistros" pelo número de sinistro.
// Os nomes dos campos abaixo devem corresponder às colunas reais da tua lista.
// Se os nomes forem diferentes, ajusta aqui o mapeamento.
// Cache da lista de sinistros para evitar chamadas repetidas
let _sinistrosCache = null;
let _condominiosCache = null; // Map de ID SharePoint → nome do condomínio

async function resolverNomeCondominio(siteId, lookupId) {
  if (!lookupId) return "";
  if (!_condominiosCache) {
    try {
      const listId = await resolverListId(SP_CONFIG.listaCondominios);
      const data = await graphGet(`/sites/${siteId}/lists/${listId}/items?$expand=fields&$top=500`);
      _condominiosCache = {};
      (data.value || []).forEach(item => {
        // Guarda por ID numérico do item (usado no LookupId)
        _condominiosCache[String(item.id)] = item.fields?.Title || "";
      });
      console.log("Condomínios carregados:", Object.keys(_condominiosCache).length);
    } catch (e) {
      console.warn("Erro a carregar condomínios:", e.message);
      _condominiosCache = {};
    }
  }
  return _condominiosCache[String(lookupId)] || "";
}
async function fetchSinistroPorNumero(numero) {
  try {
    const siteId = await resolverSiteId();
    const listId = await resolverListId(SP_CONFIG.listaSinistros);

    // Carrega todos os sinistros uma vez e guarda em cache
    if (!_sinistrosCache) {
      const data = await graphGet(`/sites/${siteId}/lists/${listId}/items?$expand=fields&$top=5000`);
      _sinistrosCache = (data.value || []).map(item => {
        const f = item.fields || {};
        // Colunas reais da lista "Listagem Sinistros" confirmadas pelo CSV
        return {
          // Mapeamento confirmado pelo console:
          // Title=OCORRÊNCIA, field_2=DataSinistro, Condom_x00ed_nioLookupId=lookup condomínio
          // field_8=Seguradora, Estado=campo choice de estado
          numeroSinistro: String(f.Title || ""),
          // Condomínio: campo Lookup — guardamos o ID para resolver depois
          condominio: f.field_3 && typeof f.field_3 === "string" ? f.field_3 : "",
          condominioid: f["Condom_x00ed_nioLookupId"] || null,
          morada: "",
          apolice: "",
          seguradora: f.field_8 || "",
          tomador: "",
          tomadorTel: "",
          tomadorEmail: "",
          perito: "",
          dataParticipacao: typeof f.field_2 === "string" ? f.field_2.slice(0, 10) : "",
          dataVistoria: "",
          estadoSinistro: f.Estado || "",
          descricao: typeof f.field_9 === "string" ? f.field_9.slice(0, 300) : "",
          processo: String(f["N_x00ba_Processo"] || f.field_1 || "")
        };
      }).filter(s => s.numeroSinistro);
      // Resolve nomes de condomínio por LookupId para sinistros sem field_3
      for (const s of _sinistrosCache) {
        if (!s.condominio && s.condominioid) {
          s.condominio = await resolverNomeCondominio(siteId, s.condominioid).catch(() => "");
        }
      }
      console.log("Sinistros carregados:", _sinistrosCache.length);
      if (data.value?.length > 0) {
        const campos = Object.keys(data.value[0].fields || {});
        console.log("Campos sinistro:", campos);
        // Log completo do primeiro item para debug de mapeamento
        const f0 = data.value[0].fields;
        const useful = Object.entries(f0).filter(([k, v]) => v && !k.startsWith("_") && !k.startsWith("@")).slice(0, 20);
        console.log("1º sinistro campos úteis:", JSON.stringify(Object.fromEntries(useful)));
      }
    }

    // Filtra localmente
    const resultados = _sinistrosCache.filter(s => s.numeroSinistro.toLowerCase().includes(numero.toLowerCase()));
    // Condomínio já vem como texto em field_3 — sem necessidade de resolução
    return resultados;
  } catch (err) {
    console.warn("Lookup sinistro falhou:", err.message);
    _sinistrosCache = null; // Reset cache para tentar novamente
    return [];
  }
}

